<template><div class="app-container"><main class="main-content"><div class="assignment-list-container"><div class="assignment-list-header"><h2>Knowledge Quiz</h2></div><ul class="assignment-list" v-if="assignments.length"><li v-for="(a,i) in assignments" :key="a.exercise_id" :class="{active:activeIndex===i}" @click="selectAssignment(i)"><h3>{{a.exercise_title}}</h3><span>{{a.course_name}}</span></li></ul><div v-else class="no-assignments">No quiz available. Check backend or demo data.</div></div><div class="assignment-detail-container"><div v-if="activeAssignment" class="assignment-detail"><h2>{{activeAssignment.exercise_title}}</h2><div v-for="q in activeAssignment.questions" :key="q.id" class="question-card"><h4 v-html="sanitizeHTML(q.content)"></h4><div v-if="q.type==='choice'"><el-radio-group v-model="answers[q.id]"><el-radio v-for="(opt,i) in JSON.parse(q.options||'[]')" :key="i" :label="String.fromCharCode(65+i)">{{opt}}</el-radio></el-radio-group></div></div><el-button type="primary" @click="submitAssignment">Submit</el-button></div><div v-else class="empty-content">Select a quiz to start</div></div></main></div></template><script>import axios from 'axios';import DOMPurify from 'dompurify';import demoQuiz from '../data/demoKnowledgeQuiz';export default{name:'Student',data(){return{assignments:demoQuiz,activeIndex:0,activeAssignment:null,answers:{},loading:false}},mounted(){this.selectAssignment(0)},methods:{sanitizeHTML(h){return h?DOMPurify.sanitize(h,{ALLOWED_TAGS:['p','br','strong','em','u','s','sub','sup'],ALLOWED_ATTR:[]}):''},selectAssignment(i){this.activeIndex=i;this.activeAssignment=this.assignments[i];this.answers={}},async submitAssignment(){this.$message.success('Submitted!')}}}</script>